  /// Real component
  @ffi.Double()
  external double i;
}

final class cpx_f_t extends ffi.Struct {
  @ffi.Float()
  external double r;

  /// Real component
  @ffi.Float()
  external double i;
}

/// Pairwise distance functions
enum DistanceMetric {
  METRIC_EUCLIDEAN(0),
  METRIC_COSINE(1),
  METRIC_HAMMING(2);

  final int value;
  const DistanceMetric(this.value);

  static DistanceMetric fromValue(int value) => switch (value) {
    0 => METRIC_EUCLIDEAN,
    1 => METRIC_COSINE,
    2 => METRIC_HAMMING,
    _ => throw ArgumentError('Unknown value for DistanceMetric: $value'),
  };
}

